def sequence(n):
    if n < 2:
        return n

    n_1 = 0
    n_2 = 1

    for _ in range(2, n + 1):
        n_2, n_1 = n_2 + 1 + n_1, n_2

    return n_2 - 1 if n % 2 == 0 else n_2

